# Terraform: locks at multiple scope levels
# Subscription-level lock (applied to a subscription resource)

resource "azurerm_subscription" "prod" {
  # Subscription data source if managing an existing subscription
}

# This creates a lock on the subscription — inherited by all resource groups
# resource "azurerm_management_lock" "sub_freeze" {
#   name       = "sub-incident-freeze"
#   scope      = data.azurerm_subscription.current.id
#   lock_level = "ReadOnly"
#   notes      = "Incident freeze — remove after investigation"
# }

# Resource group lock — inherited by all resources within
resource "azurerm_resource_group" "prod" {
  name     = "rg-prod"
  location = "eastus"
}

resource "azurerm_management_lock" "rg_prod" {
  name       = "prod-cannotdelete"
  scope      = azurerm_resource_group.prod.id  # lock scope = RG
  lock_level = "CanNotDelete"
  notes      = "Protects all resources in rg-prod from accidental deletion"
  # Terraform will destroy this lock before destroying rg-prod
  # because the scope depends on azurerm_resource_group.prod.id
}

# Individual resource lock — does NOT protect siblings, only this resource + sub-resources
resource "azurerm_storage_account" "critical" {
  name                     = "saprodcritical"
  resource_group_name      = azurerm_resource_group.prod.name
  location                 = azurerm_resource_group.prod.location
  account_tier             = "Standard"
  account_replication_type = "GRS"
}

resource "azurerm_management_lock" "sa_critical" {
  name       = "sa-critical-nodelete"
  scope      = azurerm_storage_account.critical.id  # lock scope = resource
  lock_level = "CanNotDelete"
  notes      = "This storage account has the RG lock AND its own resource lock"
}

# PowerShell: generate a full lock inventory report showing scope hierarchy
# Useful for monthly governance reports and lock health checks

param([string]$ManagementGroupId = 'mg-corp')

$report = [System.Collections.Generic.List[PSCustomObject]]::new()

$subs = (Get-AzManagementGroupSubscription -GroupId $ManagementGroupId).Id

foreach ($subId in $subs) {
    Set-AzContext -SubscriptionId $subId | Out-Null
    $subName = (Get-AzContext).Subscription.Name

    # Subscription-level locks
    Get-AzResourceLock -Scope "/subscriptions/$subId" -ErrorAction SilentlyContinue | ForEach-Object {
        $report.Add([PSCustomObject]@{
            Subscription = $subName
            Scope        = 'Subscription'
            ScopeName    = $subName
            LockName     = $_.Name
            LockLevel    = $_.Properties.Level
            Notes        = $_.Properties.Notes
            Inheritance  = 'Affects all RGs and resources in subscription'
        })
    }

    # Resource group and resource-level locks
    Get-AzResourceLock | ForEach-Object {
        $scopeType = if ($_.ResourceGroupName -and -not $_.ResourceName) { 'ResourceGroup' }
                     elseif ($_.ResourceName) { 'Resource' }
                     else { 'Unknown' }

        $inheritance = switch ($scopeType) {
            'ResourceGroup' { "Affects all $($_.ResourceGroupName) resources" }
            'Resource'      { "Affects $($_.ResourceName) and its sub-resources only" }
            default         { 'Unknown' }
        }

        $report.Add([PSCustomObject]@{
            Subscription = $subName
            Scope        = $scopeType
            ScopeName    = if ($scopeType -eq 'ResourceGroup') { $_.ResourceGroupName } else { $_.ResourceName }
            LockName     = $_.Name
            LockLevel    = $_.Properties.Level
            Notes        = $_.Properties.Notes
            Inheritance  = $inheritance
        })
    }
}

$report | Format-Table -AutoSize
$report | Export-Csv "lock-inheritance-report.csv" -NoTypeInformation
Write-Host "Report exported: lock-inheritance-report.csv ($($report.Count) entries)"
